mapper.select:
SELECT af.id, af.number, af.name, af.form_type, af.execute_timing, af.enable, af.submitter_can_revoke, af.allow_batch_process, af.allow_withdraw, af.allow_add_sign, af.duplicate_approver_rule, af.require_comment, af.organization_id, af.create_user, af.create_time, af.update_user, af.update_time, cu.name AS createUserName, uu.name AS updateUserName FROM approval_flow af LEFT JOIN sys_user cu ON af.create_user = cu.id LEFT JOIN sys_user uu ON af.update_user = uu.id WHERE af.organization_id = #{organizationId}
AND af.name LIKE CONCAT('%', #{request.name}, '%')
AND af.form_type = #{request.formType}
AND af.enable = #{request.enable}
ORDER BY af.create_time DESC

mapper.update:
UPDATE approval_flow
SET enable = 0,
    update_user = #{updateUser},
    update_time = #{updateTime}
WHERE form_type = #{formType}
  AND organization_id = #{organizationId}
  AND enable = 1

      AND id != #{excludeId}
